// The native source for the GrapheneOS/Vanadium WebView resume-freeze recovery, as
// plain strings. Kept OUT of the config plugin so two things can read it without
// pulling in expo/config-plugins: the plugin itself, and the test that checks the
// COMMITTED android/ copies still match (test/webview-recovery.test.js).
//
// Why that check exists: android/ is committed in this repo AND regenerated by
// `expo prebuild`, so these files are generated output that also lives in git. That
// is a normal prebuild-and-commit setup, but it has one failure mode - somebody edits
// the .kt in android/ (the obvious place to look), and the next prebuild silently
// overwrites it. The test turns that silent overwrite into a failed `npm run verify`.

const MODULE_KT = (pkg) => `package ${pkg}

// GENERATED by plugins/with-webview-recovery.js - do not edit here, edit the plugin.
//
// GrapheneOS/Vanadium WebView resume-freeze recovery. The cached-app freezer freezes the
// out-of-process Vanadium renderer while backgrounded; on resume its compositor never
// re-attaches to the new window surface, so it never repaints. Only a FRESH render process
// recovers it. terminate() kills just this app's renderer (API 29+, minSdk 29); the JS
// onRenderProcessGone handler reloads a fresh one. A view-remount does NOT work - it reuses
// the pooled stale renderer, which is why PearTune #110 did not fix this.

import android.os.Build
import android.view.View
import android.view.ViewGroup
import android.webkit.WebView
import com.facebook.react.bridge.Promise
import com.facebook.react.bridge.ReactApplicationContext
import com.facebook.react.bridge.ReactContextBaseJavaModule
import com.facebook.react.bridge.ReactMethod

class WebViewRecoveryModule(ctx: ReactApplicationContext) : ReactContextBaseJavaModule(ctx) {

    override fun getName() = "WebViewRecovery"

    // Resolves the number of renderers actually terminated, so the JS side can tell "recovered"
    // from "nothing to do" rather than assuming.
    @ReactMethod
    fun terminateRenderer(promise: Promise) {
        val activity = reactApplicationContext.currentActivity
        if (activity == null) { promise.resolve(0); return }
        activity.runOnUiThread {
            try {
                if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q) { promise.resolve(0); return@runOnUiThread }
                val root = activity.window?.decorView
                var terminated = 0
                for (wv in findWebViews(root)) {
                    if (wv.webViewRenderProcess?.terminate() == true) terminated++
                }
                promise.resolve(terminated)
            } catch (e: Throwable) { promise.reject("terminate_failed", e) }
        }
    }

    private fun findWebViews(view: View?): List<WebView> {
        if (view == null) return emptyList()
        val out = ArrayList<WebView>()
        val stack = ArrayDeque<View>()
        stack.addLast(view)
        while (stack.isNotEmpty()) {
            val v = stack.removeLast()
            if (v is WebView) out.add(v)
            if (v is ViewGroup) for (i in 0 until v.childCount) stack.addLast(v.getChildAt(i))
        }
        return out
    }
}
`

const PACKAGE_KT = (pkg) => `package ${pkg}

// GENERATED by plugins/with-webview-recovery.js - do not edit here, edit the plugin.

import android.view.View
import com.facebook.react.ReactPackage
import com.facebook.react.bridge.NativeModule
import com.facebook.react.bridge.ReactApplicationContext
import com.facebook.react.uimanager.ReactShadowNode
import com.facebook.react.uimanager.ViewManager

class WebViewRecoveryPackage : ReactPackage {
    override fun createNativeModules(ctx: ReactApplicationContext): List<NativeModule> =
        listOf(WebViewRecoveryModule(ctx))

    override fun createViewManagers(ctx: ReactApplicationContext): List<ViewManager<View, ReactShadowNode<*>>> =
        emptyList()
}
`

// The one line that registers the package with React Native, inserted into the
// generated MainApplication.kt. Exactly once: RN throws on a duplicate module name, so
// a second add() would be a launch crash, not a warning.
const REGISTER_CALL = 'add(WebViewRecoveryPackage())'

module.exports = { MODULE_KT, PACKAGE_KT, REGISTER_CALL }
